import axios from 'axios';
import React, { Component } from 'react';
import withRouter from '../utils/withRouter';

class ProductDetail extends Component {
  constructor(props) {
    super(props);
    this.state = { product: null };
  }

  render() {
    const item = this.state.product;
    if (!item) return <div className="align-center"><h2>LOADING...</h2></div>;

    return (
      <div className="align-center">
        <h2 className="text-center">PRODUCT DETAIL</h2>
        <table className="align-center">
          <tbody>
            <tr><td rowSpan="5"><img src={'data:image/jpg;base64,' + item.image} width="350" height="350" alt="" /></td><td>ID: {item._id}</td></tr>
            <tr><td>Name: {item.name}</td></tr>
            <tr><td>Price: {item.price}</td></tr>
            <tr><td>Category: {item.category?.name}</td></tr>
            <tr><td>Creation date: {new Date(item.cdate).toLocaleString()}</td></tr>
          </tbody>
        </table>
      </div>
    );
  }

  componentDidMount() {
    axios.get('/api/customer/products/' + this.props.params.id).then((res) => this.setState({ product: res.data }));
  }
}

export default withRouter(ProductDetail);
